import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef, type ComponentRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import { CloseButton } from '../close-button';
import styles from './Tag.module.css';

type TagVariant = 'default' | 'secondary' | 'outline' | 'ghost' | 'destructive';
type TagSize = 'sm' | 'md';
type TagRootProps = HTMLArkProps<'span'> & {
  variant?: TagVariant;
  size?: TagSize;
};
type TagLabelProps = HTMLArkProps<'span'>;
type TagStartElementProps = HTMLArkProps<'span'>;
type TagEndElementProps = HTMLArkProps<'span'>;
type TagCloseTriggerProps = HTMLArkProps<'button'>;

const DEFAULT_CLOSE_LABEL = 'Remove tag';

const TagRoot = forwardRef<HTMLSpanElement, TagRootProps>(function TagRoot(
  { className, size = 'md', variant = 'default', ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      {...props}
      data-scope="tag"
      data-part="root"
      data-slot="tag-root"
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
    />
  );
});

const TagLabel = forwardRef<HTMLSpanElement, TagLabelProps>(function TagLabel(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      {...props}
      data-scope="tag"
      data-part="label"
      data-slot="tag-label"
      className={clsx(styles.label, normalizeClassName(className))}
    />
  );
});

const TagStartElement = forwardRef<HTMLSpanElement, TagStartElementProps>(function TagStartElement(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      {...props}
      data-scope="tag"
      data-part="start-element"
      data-slot="tag-start-element"
      className={clsx(styles.startElement, normalizeClassName(className))}
    />
  );
});

const TagEndElement = forwardRef<HTMLSpanElement, TagEndElementProps>(function TagEndElement(
  { className, ...props },
  ref,
) {
  return (
    <ark.span
      ref={ref}
      {...props}
      data-scope="tag"
      data-part="end-element"
      data-slot="tag-end-element"
      className={clsx(styles.endElement, normalizeClassName(className))}
    />
  );
});

const TagCloseTrigger = forwardRef<ComponentRef<typeof CloseButton.Root>, TagCloseTriggerProps>(
  function TagCloseTrigger(
    {
      asChild,
      className,
      children,
      'aria-label': ariaLabel,
      'aria-labelledby': ariaLabelledBy,
      ...props
    },
    ref,
  ) {
    return (
      <CloseButton.Root
        ref={ref}
        asChild={asChild}
        {...props}
        data-scope="tag"
        data-part="close-trigger"
        data-slot="tag-close-trigger"
        aria-label={
          ariaLabel ??
          (!asChild && children == null && ariaLabelledBy == null ? DEFAULT_CLOSE_LABEL : undefined)
        }
        aria-labelledby={ariaLabelledBy}
        className={clsx(styles.closeTrigger, normalizeClassName(className))}
      >
        {children}
      </CloseButton.Root>
    );
  },
);

const Tag = Object.assign(TagRoot, {
  Root: TagRoot,
  Label: TagLabel,
  StartElement: TagStartElement,
  EndElement: TagEndElement,
  CloseTrigger: TagCloseTrigger,
});

export { Tag };

@layer moduix.components {
  .root {
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    min-width: 0;
    box-sizing: border-box;
    align-items: center;
    gap: var(--moduix-tag-gap, var(--moduix-spacing-1-5));
    border: var(--moduix-tag-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-tag-border-color, transparent);
    border-radius: var(--moduix-tag-radius, var(--moduix-radius-full));
    background-color: var(--moduix-tag-bg, var(--moduix-color-primary));
    color: var(--moduix-tag-color, var(--moduix-color-primary-foreground));
    font-size: var(--moduix-tag-font-size, var(--moduix-text-xs));
    font-weight: var(--moduix-tag-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-tag-line-height, var(--moduix-line-height-text-xs));
    min-height: var(--moduix-tag-height-md, var(--moduix-size-xs));
    padding-block: var(--moduix-tag-padding-y-md, var(--moduix-spacing-0-5));
    padding-inline: var(--moduix-tag-padding-x-md, var(--moduix-spacing-2));
    white-space: nowrap;
    vertical-align: middle;
    transition:
      color var(--moduix-tag-transition, var(--moduix-transition-default)),
      background-color var(--moduix-tag-transition, var(--moduix-transition-default)),
      border-color var(--moduix-tag-transition, var(--moduix-transition-default));

    > svg {
      width: var(--moduix-tag-icon-size, var(--moduix-spacing-3));
      height: var(--moduix-tag-icon-size, var(--moduix-spacing-3));
      flex-shrink: 0;
      pointer-events: none;
    }

    &[data-size='sm'] {
      gap: var(--moduix-tag-gap-sm, var(--moduix-spacing-1));
      min-height: var(--moduix-tag-height-sm, 1.25rem);
      padding-block: var(--moduix-tag-padding-y-sm, 0);
      padding-inline: var(--moduix-tag-padding-x-sm, var(--moduix-spacing-1-5));
    }

    &[data-variant='secondary'] {
      background-color: var(--moduix-tag-bg, var(--moduix-color-secondary));
      border-color: var(--moduix-tag-border-color, transparent);
      color: var(--moduix-tag-color, var(--moduix-color-secondary-foreground));
    }

    &[data-variant='outline'],
    &[data-variant='ghost'] {
      background-color: var(--moduix-tag-bg, transparent);
      color: var(--moduix-tag-color, var(--moduix-color-foreground));
    }

    &[data-variant='outline'] {
      border-color: var(--moduix-tag-border-color, var(--moduix-color-border));
    }

    &[data-variant='destructive'] {
      background-color: var(--moduix-tag-bg, var(--moduix-color-destructive));
      border-color: var(--moduix-tag-border-color, transparent);
      color: var(--moduix-tag-color, var(--moduix-color-destructive-foreground));
    }
  }

  .label {
    min-width: 0;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .startElement,
  .endElement {
    display: inline-flex;
    min-width: 0;
    flex-shrink: 0;
    align-items: center;
    justify-content: center;

    > svg {
      width: var(--moduix-tag-icon-size, var(--moduix-spacing-3));
      height: var(--moduix-tag-icon-size, var(--moduix-spacing-3));
      flex-shrink: 0;
      pointer-events: none;
    }
  }

  .closeTrigger {
    --moduix-close-button-size: var(--moduix-tag-close-trigger-size, var(--moduix-spacing-4));
    --moduix-close-button-radius: var(--moduix-tag-close-trigger-radius, var(--moduix-radius-full));
    --moduix-close-button-icon-size: var(
      --moduix-tag-close-trigger-icon-size,
      var(--moduix-spacing-2-5)
    );
    --moduix-close-button-bg: var(--moduix-tag-close-trigger-bg, transparent);
    --moduix-close-button-bg-hover: var(
      --moduix-tag-close-trigger-bg-hover,
      color-mix(in oklab, currentColor 12%, transparent)
    );
    --moduix-close-button-color: inherit;
    --moduix-close-button-color-hover: inherit;
    --moduix-close-button-disabled-opacity: var(
      --moduix-tag-disabled-opacity,
      var(--moduix-opacity-disabled)
    );
    --moduix-close-button-focus-ring-width: var(
      --moduix-tag-close-trigger-focus-ring-width,
      var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
    );
    --moduix-close-button-focus-ring-color: var(
      --moduix-tag-close-trigger-focus-ring-color,
      var(--moduix-color-ring)
    );
    --moduix-close-button-focus-ring-offset: var(--moduix-tag-close-trigger-focus-ring-offset, 0);
    --moduix-close-button-transition: var(
      --moduix-tag-transition,
      var(--moduix-transition-default)
    );
  }
}
